const CAP_EUR = 3.00;
const rows = $input.all();
const row = rows.length > 0 ? rows[0].json : {};
const cost = parseFloat(row.total_cost_eur || '0');
return [{ json: {
  success: true,
  data: {
    year_month: row.year_month || new Date().toISOString().slice(0, 7),
    total_input_tokens: parseInt(row.total_input_tokens || '0'),
    total_output_tokens: parseInt(row.total_output_tokens || '0'),
    total_cost_eur: cost,
    cap_eur: CAP_EUR,
    percent_used: Math.round((cost / CAP_EUR) * 100),
    last_updated: row.last_updated || null
  },
  meta: { timestamp: new Date().toISOString() }
} }];
